module RefModule(
    input                 clk,
    input                 rst,
    input                 en,
    input                 up_down,

    output reg [2:0]      count
);

// Up/down counter implementation
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        count <= 3'd0;
    else if (en) begin
        if (up_down)
            count <= count + 3'd1;
        else
            count <= count - 3'd1;
    end
end

endmodule
